.ds-text {
  margin: 0;
  font-family: var(--typography-font-family);
}

/* ── Variant: size / leading / (caption) case ───────────────────────────── */

.ds-text--display-medium {
  font-size: var(--typography-fontsize-3xl);
  line-height: var(--typography-lineheight-3xl);
}

.ds-text--display-small {
  font-size: var(--typography-fontsize-2xl);
  line-height: var(--typography-lineheight-2xl);
}

.ds-text--title-large {
  font-size: var(--typography-fontsize-xl);
  line-height: var(--typography-lineheight-xl);
}

.ds-text--title-medium {
  font-size: var(--typography-fontsize-lg);
  line-height: var(--typography-lineheight-lg);
}

.ds-text--title-small {
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
}

.ds-text--body-large {
  font-size: var(--typography-fontsize-lg);
  line-height: var(--typography-lineheight-lg);
}

.ds-text--body-medium {
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
}

.ds-text--body-small {
  font-size: var(--typography-fontsize-sm);
  line-height: var(--typography-lineheight-sm);
}

.ds-text--caption {
  font-size: var(--typography-fontsize-xs);
  line-height: var(--typography-lineheight-xs);
  text-transform: uppercase;
}

/* ── Emphasis: weight + letter-spacing ──────────────────────────────────── */

.ds-text--display-medium.ds-text--emphasis,
.ds-text--display-small.ds-text--emphasis {
  font-weight: var(--typography-weight-bold);
  letter-spacing: var(--typography-letterspacing-negative-double);
}

.ds-text--display-medium.ds-text--regular,
.ds-text--display-small.ds-text--regular {
  font-weight: var(--typography-weight-regular);
  letter-spacing: var(--typography-letterspacing-negative);
}

.ds-text--title-large.ds-text--emphasis {
  font-weight: var(--typography-weight-semibold);
  letter-spacing: var(--typography-letterspacing-negative-double);
}

.ds-text--title-large.ds-text--regular {
  font-weight: var(--typography-weight-regular);
  letter-spacing: var(--typography-letterspacing-negative);
}

.ds-text--title-medium.ds-text--emphasis,
.ds-text--title-small.ds-text--emphasis {
  font-weight: var(--typography-weight-semibold);
  letter-spacing: var(--typography-letterspacing-negative);
}

.ds-text--title-medium.ds-text--regular,
.ds-text--title-small.ds-text--regular {
  font-weight: var(--typography-weight-regular);
  letter-spacing: var(--typography-letterspacing-negative-half);
}

.ds-text--body-large.ds-text--emphasis,
.ds-text--body-medium.ds-text--emphasis {
  font-weight: var(--typography-weight-medium);
  letter-spacing: var(--typography-letterspacing-negative);
}

.ds-text--body-large.ds-text--regular,
.ds-text--body-medium.ds-text--regular {
  font-weight: var(--typography-weight-regular);
  letter-spacing: var(--typography-letterspacing-negative-half);
}

.ds-text--body-small.ds-text--emphasis {
  font-weight: var(--typography-weight-medium);
  letter-spacing: var(--typography-letterspacing-negative-half);
}

.ds-text--body-small.ds-text--regular {
  font-weight: var(--typography-weight-regular);
  letter-spacing: var(--typography-letterspacing-none);
}

.ds-text--caption.ds-text--emphasis {
  font-weight: var(--typography-weight-semibold);
  letter-spacing: var(--typography-letterspacing-positive);
}

.ds-text--caption.ds-text--regular {
  font-weight: var(--typography-weight-medium);
  letter-spacing: var(--typography-letterspacing-positive);
}

/* ── Truncation ─────────────────────────────────────────────────────────── */

.ds-text--truncate-1 {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.ds-text--truncate-2,
.ds-text--truncate-3,
.ds-text--truncate-4,
.ds-text--truncate-5 {
  overflow: hidden;
  display: -webkit-box;
  -webkit-box-orient: vertical;
  text-overflow: ellipsis;
  word-break: break-word;
}

.ds-text--truncate-2 { -webkit-line-clamp: 2; }
.ds-text--truncate-3 { -webkit-line-clamp: 3; }
.ds-text--truncate-4 { -webkit-line-clamp: 4; }
.ds-text--truncate-5 { -webkit-line-clamp: 5; }

/* ── Wrap ───────────────────────────────────────────────────────────────── */

.ds-text--nowrap {
  white-space: nowrap;
  word-break: normal;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}

.ds-text--balance { text-wrap: balance; }
.ds-text--pretty  { text-wrap: pretty; }

/* ── Color ──────────────────────────────────────────────────────────────── */

.ds-text--color-primary   { color: var(--color-foreground-primary); }
.ds-text--color-secondary { color: var(--color-foreground-secondary); }
.ds-text--color-tertiary  { color: var(--color-foreground-tertiary); }
.ds-text--color-brand     { color: var(--color-foreground-bold-brand); }
.ds-text--color-negative  { color: var(--color-foreground-bold-negative); }
.ds-text--color-positive  { color: var(--color-foreground-bold-positive); }
.ds-text--color-warning   { color: var(--color-foreground-bold-warning); }
.ds-text--color-caution   { color: var(--color-foreground-bold-caution); }
.ds-text--color-ai        { color: var(--color-foreground-bold-ai); }
.ds-text--color-on-strong { color: var(--color-foreground-on-strong-background-primary); }
.ds-text--color-on-bold   { color: var(--color-foreground-on-bold-background-primary); }
.ds-text--color-inherit   { color: inherit; }

/* ── Decorations ─────────────────────────────────────────────────────────── */

.ds-text--decoration-underline {
  text-decoration: underline;
  text-underline-offset: 2px;
  text-decoration-thickness: 1px;
}

.ds-text--decoration-dotted-underline {
  text-decoration: underline dotted;
  text-underline-offset: 2px;
  text-decoration-thickness: 1px;
}

/* ── Style ──────────────────────────────────────────────────────────────── */

.ds-text--italic { font-style: italic; }

.ds-text--font-feature-tabular-nums {
  font-variant-numeric: tabular-nums;
  font-feature-settings: 'tnum';
}

/* ── Align ──────────────────────────────────────────────────────────────── */

.ds-text--align-left   { text-align: left; }
.ds-text--align-center { text-align: center; }
.ds-text--align-right  { text-align: right; }

import { Component, Prop, h, Host } from '@stencil/core';
import { textVariantClass } from './text-utils';

export type TextVariant =
  | 'text-display-medium'
  | 'text-display-small'
  | 'text-title-large'
  | 'text-title-medium'
  | 'text-title-small'
  | 'text-body-large'
  | 'text-body-medium'
  | 'text-body-small'
  | 'text-caption';

export type TextColorToken =
  | 'primary' | 'secondary' | 'tertiary'
  | 'brand' | 'negative' | 'positive' | 'warning' | 'caution' | 'ai'
  | 'on-strong' | 'on-bold' | 'inherit';

export type TextColor = TextColorToken | `var(--${string})`;
export type TextDecoration = 'none' | 'underline' | 'dotted-underline';
export type TextAlign = 'left' | 'center' | 'right';
export type LineTruncation = 1 | 2 | 3 | 4 | 5 | 'none';
export type TextWrap = 'wrap' | 'nowrap' | 'balance' | 'pretty';
export type TextElement = 'p' | 'span' | 'div' | 'label' | 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';
export type TextFontFeature = 'normal' | 'tabular-nums';

@Component({
  tag: 'ds-text',
  styleUrl: 'Text.css',
  scoped: true,
})
export class Text {
  @Prop() variant: TextVariant = 'text-body-medium';
  /**
   * Heavier weight + tighter letter-spacing for the variant.
   * `false` (default): regular weight (caption stays medium).
   * `true`: display bold, title/caption semibold, body medium.
   */
  @Prop() emphasis: boolean = false;
  @Prop() color: TextColor | undefined;
  @Prop() decoration: TextDecoration | undefined;
  @Prop() italic: boolean = false;
  @Prop() align: TextAlign | undefined;
  @Prop() lineTruncation: LineTruncation = 'none';
  @Prop() wrap: TextWrap | undefined;
  @Prop() fontFeature: TextFontFeature = 'normal';
  @Prop() as: TextElement = 'p';
  /** Maps to `for` attribute on <label> elements. */
  @Prop() for: string | undefined;
  /** Forwarded to the inner element (e.g. aria-labelledby targets). */
  @Prop() textId: string | undefined;

  render() {
    // Polymorphic element: TSX treats a variable tag as a component, so a
    // dynamic intrinsic element name must be cast to `any` to render.
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const Tag = this.as as any;
    const isCustomColor = (c: TextColor) => typeof c === 'string' && c.startsWith('var(--');

    const cls: Record<string, boolean> = {
      'ds-text': true,
      [textVariantClass(this.variant)]: true,
      'ds-text--emphasis': this.emphasis,
      'ds-text--regular': !this.emphasis,
      'ds-text--nowrap': this.wrap === 'nowrap',
      'ds-text--balance': this.wrap === 'balance',
      'ds-text--pretty': this.wrap === 'pretty',
      'ds-text--truncate-1': this.lineTruncation === 1 && this.wrap !== 'nowrap',
      'ds-text--truncate-2': this.lineTruncation === 2 && this.wrap !== 'nowrap',
      'ds-text--truncate-3': this.lineTruncation === 3 && this.wrap !== 'nowrap',
      'ds-text--truncate-4': this.lineTruncation === 4 && this.wrap !== 'nowrap',
      'ds-text--truncate-5': this.lineTruncation === 5 && this.wrap !== 'nowrap',
      'ds-text--color-primary':   this.color === 'primary',
      'ds-text--color-secondary': this.color === 'secondary',
      'ds-text--color-tertiary':  this.color === 'tertiary',
      'ds-text--color-brand':     this.color === 'brand',
      'ds-text--color-negative':  this.color === 'negative',
      'ds-text--color-positive':  this.color === 'positive',
      'ds-text--color-warning':   this.color === 'warning',
      'ds-text--color-caution':   this.color === 'caution',
      'ds-text--color-ai':        this.color === 'ai',
      'ds-text--color-on-strong': this.color === 'on-strong',
      'ds-text--color-on-bold':   this.color === 'on-bold',
      'ds-text--color-inherit':   this.color === 'inherit',
      'ds-text--decoration-underline':        this.decoration === 'underline',
      'ds-text--decoration-dotted-underline': this.decoration === 'dotted-underline',
      'ds-text--italic': this.italic,
      'ds-text--align-left':   this.align === 'left',
      'ds-text--align-center': this.align === 'center',
      'ds-text--align-right':  this.align === 'right',
      'ds-text--font-feature-tabular-nums': this.fontFeature === 'tabular-nums',
    };

    const style = this.color && isCustomColor(this.color)
      ? { color: this.color as string }
      : undefined;

    const extraProps: Record<string, string> = {};
    if (this.as === 'label' && this.for) extraProps['for'] = this.for;
    if (this.textId) extraProps['id'] = this.textId;

    return (
      <Host style={{ display: 'contents' }}>
        <Tag class={cls} style={style} {...extraProps}>
          <slot />
        </Tag>
      </Host>
    );
  }
}

import type { TextVariant } from './Text';

/** `text-body-medium` → `ds-text--body-medium` */
export function textVariantClass(variant: TextVariant): string {
  return `ds-text--${variant.replace(/^text-/, '')}`;
}
